   serializes an `aria-expanded` attribute set via setAttribute, and the
   reveal-rule contract in app.css.test.ts anchors on that exact text.
   prettier-ignore so the repo's singleQuote config doesn't rewrite it. */
/* prettier-ignore */
.browse-table tbody tr:hover .row-menu-btn,
.row-menu-btn[aria-expanded="true"] {
  opacity: 1;
  pointer-events: auto;
}
.row-menu-btn:hover {
  color: #e6e6e6;
}


